import { useState } from 'react';
import axiosInstance from '../axiosConfig';

const BookTable = () => {
  const [step, setStep] = useState(1);
  const [searchData, setSearchData] = useState({ dateTime: '', numGuests: 1 });
  const [availableTables, setAvailableTables] = useState([]);
  const [selectedTable, setSelectedTable] = useState(null);
  const [formData, setFormData] = useState({ customerName: '', email: '', phoneNum: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [confirmation, setConfirmation] = useState(null);

  // Step 1 — search available tables
  const handleSearch = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axiosInstance.get('/api/tables/available', {
        params: {
          dateTime: searchData.dateTime,
          numGuests: searchData.numGuests
        }
      });
      if (response.data.length === 0) {
        setError('No tables available at this time. Please try a different date or time.');
      } else {
        setAvailableTables(response.data);
        setStep(2);
      }
    } catch (err) {
      setError('Failed to check availability. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // Step 2 — select a table
  const handleSelectTable = (table) => {
    setSelectedTable(table);
    setStep(3);
  };

  // Step 3 — submit booking
  const handleBooking = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axiosInstance.post('/api/reservations', {
        ...formData,
        reservedDate: searchData.dateTime,
        numGuests: searchData.numGuests,
        tableId: selectedTable._id
      });
      setConfirmation(response.data.reservation);
      setStep(4);
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto mt-10 px-4">
      <h1 className="text-3xl font-bold text-center mb-8 text-blue-700">
        Book a Table
      </h1>

      {/* Progress indicator */}
      <div className="flex justify-center mb-8 gap-2">
        {['Date & Time', 'Select Table', 'Your Details', 'Confirmed'].map((label, i) => (
          <div key={i} className="flex items-center gap-2">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold
              ${step === i + 1 ? 'bg-blue-600 text-white' :
                step > i + 1 ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-600'}`}>
              {i + 1}
            </div>
            <span className="text-sm hidden sm:block">{label}</span>
            {i < 3 && <div className="w-6 h-px bg-gray-300" />}
          </div>
        ))}
      </div>

      {error && (
        <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-sm">
          {error}
        </div>
      )}

      {/* Step 1 — Date, time, guests */}
      {step === 1 && (
        <form onSubmit={handleSearch} className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-4">When would you like to visit?</h2>
          <label className="block text-sm font-medium mb-1">Date and Time</label>
          <input
            type="datetime-local"
            value={searchData.dateTime}
            onChange={(e) => setSearchData({ ...searchData, dateTime: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Number of Guests</label>
          <input
            type="number"
            min="1"
            max="20"
            value={searchData.numGuests}
            onChange={(e) => setSearchData({ ...searchData, numGuests: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 text-white p-2 rounded hover:bg-blue-700 transition disabled:opacity-50"
          >
            {loading ? 'Checking availability...' : 'Check Availability'}
          </button>
        </form>
      )}

      {/* Step 2 — Select table */}
      {step === 2 && (
        <div className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-4">Select a Table</h2>
          <p className="text-sm text-gray-500 mb-4">
            {availableTables.length} table(s) available on{' '}
            {new Date(searchData.dateTime).toLocaleString()} for {searchData.numGuests} guest(s)
          </p>
          <div className="grid grid-cols-1 gap-4">
            {availableTables.map((table) => (
              <div
                key={table._id}
                className="border rounded p-4 flex justify-between items-center hover:border-blue-500 cursor-pointer transition"
                onClick={() => handleSelectTable(table)}
              >
                <div>
                  <p className="font-semibold">{table.location}</p>
                  <p className="text-sm text-gray-500">Seats up to {table.seats} guests</p>
                  {table.babyHighChair && (
                    <p className="text-xs text-green-600 mt-1">Baby high chair available</p>
                  )}
                </div>
                <button className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition">
                  Select
                </button>
              </div>
            ))}
          </div>
          <button
            onClick={() => setStep(1)}
            className="mt-4 text-sm text-blue-600 hover:underline"
          >
            Back
          </button>
        </div>
      )}

      {/* Step 3 — Contact details */}
      {step === 3 && (
        <form onSubmit={handleBooking} className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-1">Your Details</h2>
          <p className="text-sm text-gray-500 mb-4">
            Table: {selectedTable.location} — {new Date(searchData.dateTime).toLocaleString()}
          </p>
          <label className="block text-sm font-medium mb-1">Full Name</label>
          <input
            type="text"
            placeholder="John Smith"
            value={formData.customerName}
            onChange={(e) => setFormData({ ...formData, customerName: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Email</label>
          <input
            type="email"
            placeholder="john@example.com"
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Phone Number</label>
          <input
            type="tel"
            placeholder="0400 000 000"
            value={formData.phoneNum}
            onChange={(e) => setFormData({ ...formData, phoneNum: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-green-600 text-white p-2 rounded hover:bg-green-700 transition disabled:opacity-50"
          >
            {loading ? 'Confirming...' : 'Confirm Booking'}
          </button>
          <button
            type="button"
            onClick={() => setStep(2)}
            className="mt-3 w-full text-sm text-blue-600 hover:underline"
          >
            Back
          </button>
        </form>
      )}

      {/* Step 4 — Confirmation */}
      {step === 4 && confirmation && (
        <div className="bg-white p-6 shadow rounded text-center">
          <div className="text-green-500 text-5xl mb-4">✓</div>
          <h2 className="text-2xl font-bold mb-2">Booking Confirmed!</h2>
          <p className="text-gray-600 mb-4">
            A confirmation SMS has been sent to your phone.
          </p>
          <div className="bg-gray-50 rounded p-4 text-left mb-4">
            <p><span className="font-medium">Name:</span> {confirmation.customerName}</p>
            <p><span className="font-medium">Date:</span> {new Date(confirmation.reservedDate).toLocaleString()}</p>
            <p><span className="font-medium">Guests:</span> {confirmation.numGuests}</p>
            <p className="mt-2 text-sm text-gray-500">
              Your Reservation ID:
            </p>
            <p className="font-mono font-bold text-blue-700 break-all">{confirmation._id}</p>
            <p className="text-xs text-gray-400 mt-1">
              Keep this ID — you will need it to view or modify your reservation.
            </p>
          </div>
          <button
            onClick={() => { setStep(1); setConfirmation(null); setFormData({ customerName: '', email: '', phoneNum: '' }); }}
            className="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700 transition"
          >
            Make Another Booking
          </button>
        </div>
      )}
    </div>
  );
};

export default BookTable;
